var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"저 여자, 상당한 몸놀림이야.","JPN":"あの女、相当な身のこなしだな。","ENG":"That girl, her movement is impeccable.","TWN":"那個女人，身手很出色。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"역시 구형 어보미네이션으로 상대하긴 무리였나?","JPN":"やはり旧型のアボミネーションで相手するのは無理だったか？","ENG":"I should've known that the early model Abomination wouldn't stand a chance.","TWN":"舊型憎惡果然不足以對付她嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"파우스트님!","JPN":"ファウスト様！","ENG":"Sir!","TWN":"浮士德！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"방금 보고가 들어왔습니다. 습격했던 이들이 시설 내부로 침입했다고 합니다.","JPN":"ただいま報告が入りました。襲撃した者たちが、施設の内部に侵入したようです。","ENG":"A report has just come in. The ones who ambushed us have infiltrated this facility.","TWN":"剛剛收到報告，襲擊者已經進到設施內部。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"현재 병력만으로는 저 그림자들을 상대하기에도 벅찬 상황입니다. 어떻게 하시겠습니까?","JPN":"現在の兵力だけではあのシャドウたちを相手することも難しい状況です。いかがなさいますか？","ENG":"However, our troops are currently overwhelmed dealing with the Shadows. What should we do?","TWN":"以目前的兵力，光是對付那些暗影就已經很吃力，我們該怎麼辦？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"아, 불청객이란 말이지?","JPN":"ああ、招かれざる客ってことだな？","ENG":"Oh, you mean our uninvited guests?","TWN":"呵，是不速之客嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"잘됐네. 순조롭게 진입할 수 있도록 해 줘.","JPN":"ちょうどいい。すんなりと進入できるようにしてやれ。","ENG":"Good. Let them come in.","TWN":"正好，就放她們進來吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"우리 전력으로 양측을 모두 막기에는 불가능하잖아?","JPN":"僕たちの戦力で両方とも止めるのは無理だろう？","ENG":"We don't have enough men to stop both armies, right?","TWN":"以我們的戰力，現在沒辦法同時應付二幫人吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"반면에 저 둘은 협력할 만한 사이로는 안 보여.","JPN":"その反面、両者は協力するような間柄には見えない。","ENG":"However, it also doesn't look like those two will cooperate.","TWN":"而且她們看起來也不像是合作關係。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"서로 대면하게 해 주면 어떻게 될지, 궁금하지 않아?","JPN":"ばったり会ったらどうなるか、気にならないか？","ENG":"So, I'm curious to see what will happen if they encounter each other. Aren't you?","TWN":"我很好奇，如果她們遇到會發生什麼事？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"분위기가 어째 묘하네요. 꽤 깊숙하게 들어온 것 같은데 총알 한 발 안 날아와요.","JPN":"雰囲気が妙ですね。かなり奥まで来たと思うんですが、弾一発も飛んで来ないなんて。","ENG":"This feels a little strange. I think we're in pretty deep, but I haven't heard a single gunshot yet.","TWN":"奇怪，我們明明已經深入內部，為什麼沒有遇到任何阻攔？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"보통은 함정에 걸렸을 때나 이러는데….","JPN":"普通、こういう場合は罠である可能性が……","ENG":"This usually only happens when it's a trap...","TWN":"這該不會是陷阱吧……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"─어?","JPN":"──え？","ENG":"–Huh?","TWN":"─嗯？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우와왓!?","JPN":"あわわっ！？","ENG":"WHOA!!","TWN":"哎呀？！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"칫, 반응이 빠르네. 확실하게 목을 꿰뚫어 버리려고 했는데.","JPN":"チッ、反応が早いわね。確実に首を貫くつもりだったのに。","ENG":"Tch, good reflexes. I was certain that this strike would pierce your neck.","TWN":"嘖，反應很快嘛，本來想一次就刺穿你的脖子。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};